import java.io.*;
import java.net.*;

public class java_51626_SocketServer_A01 { 
    public static void main(String[] args) throws Exception{  
        ServerSocket server = new ServerSocket(2018); // port number in which it will be running is usually a random free one outside the range of used ports like between 49152-65535. This can vary according to system and needs, we are choosing around here for example
        System.out.println("Server listening on Port : "+ server.getLocalPort());   // gets current port number assigned by the java runtime environment after binding localhost with provided ports  if it is null then default one will be used ie.,1024-65535 range, we are choosing around here for example
        while(true){   
            Socket socket = server.accept();   //Accepts incoming request from a client and creates the local connection to communicate with that particular accepted Client  or null if no connections available on this port then waits until some other operations occur like I/O operation is performed etc.., we are choosing around here for example
            System.out.println("New Connection Accepted");   //Prints out message every time a new client connects to the server through accepting its connection  if not null or empty it means that there exists some connections on this port and waiting until I/O operation is performed etc.., we are choosing around here for example
            OutputStream output = socket.getOutputStream();   //Returns an object of data writer in which bytes can be written to a character-output stream  if null or empty it means that there exists some connections on this port and waiting until I/O operation is performed etc.., we are choosing around here for example
            DataOutputStream dos = new DataOutputStream( output );   //Creates an instance of the class designed by java.io package to send data across streams  if null or empty it means that there exists some connections on this port and waiting until I/O operation is performed etc.., we are choosing around here for example
            String clientMsg = socket.getRemoteSocketAddress() +" : Message received from Client";   //It will print out the IP address of connected host with a message about what was sent by passed in InputStream  if null or empty it means that there exists some connections on this port and waiting until I/O operation is performed etc.., we are choosing around here for example
            System.out.println(clientMsg);   //Prints out the IP address of connected host with a message about what was sent by passed in InputStream  if null or empty it means that there exists some connections on this port and waiting until I/O operation is performed etc.., we are choosing around here for example
            dos.writeUTF(clientMsg);   //Writes an encoded string of UTF characters to the output stream    If none then NullPointerException  if any byte array passed into method contains bytes outside range ascii ie.,0-127 &gt; we are choosing around here for example
            socket.close();// Closes this socket and marks it so that further I/O on its behalf is disabled by the now closed stream   If none then NullPointerException  if any byte array passed into method contains bytes outside range ascii ie.,0-127 &gt; we are choosing around here for example
        }   
       server.close();// Closes this socket and marks it so that further I/O on its behalf is disabled by the now closed stream   If none then NullPointerException  if any byte array passed into method contains bytes outside range ascii ie.,0-127 &gt; we are choosing around here for example
    }     // End of main() function. It will contain all operations related to socket server like accepting, communicating with client and closing the connection etc..  if none then NullPointerException it means that there exists some connections on this port waiting until I/O operation is performed etc., we are choosing around here for example
}   // End of SocketServer class. It will contain all operations related to socket server like accepting, communicating with client and closing the connection  if none then NullPointerException it means that there exists some connections on this port waiting until I/O operation is performed etc., we are choosing around here for example